def tr(text): return KEY_TR.get(text.strip(), text.strip())
def tr_group(text): return GROUP_TR.get(text.strip(), text.strip())

_UNITS = [("л/100км","l/100km"),("л/100 км","l/100km"),("км/ч","km/saat"),("об/мин","d/d"),("л.с.","a.g."),("см³","sm³"),("мм","mm"),("кг","kq"),("Нм","Nm"),("кВт","kVt"),("г/км","q/km"),("АИ-","AI-"),("Евро ","Avro "),(" при "," @ "),(" л"," l")]

def tr_val(text):
    t = tr(text)
    for ru, az in _UNITS: t = t.replace(ru, az)
    return t

def make_specs(raw):
    result, sort = [], 0
    for gn, items in raw.items():
        sort += 1
        result.append({"label": tr_group(gn), "sort_order": sort, "items": [{"key": tr(k), "value": tr_val(v)} for k, v in items]})
    return result

def make_modification_specs(mods):
    return {"modifications": [{"name": n, "groups": make_specs(r)} for n, r in mods]}

def get_db(): return psycopg2.connect(**DB_CONFIG)

def _mt(s, g=6):
    n = {}
    for gp, items in s.items(): n[gp] = [(k, "Механика" if k == "Коробка передач" else str(g) if k == "Количество передач" else v) for k, v in items]
    return n

def _drv(s, d="Передний"):
    n = {}
    for gp, items in s.items(): n[gp] = [(k, d if k == "Тип привода" else v) for k, v in items]
    return n

def _s(spec, **kw):
    MAP = {"power": "Максимальная мощность", "torque": "Максимальный крутящий момент", "displacement": "Объём двигателя", "turbo": "Наддув", "fuel_type": "Тип двигателя", "config": "Конфигурация", "cylinders": "Количество цилиндров", "valves": "Количество клапанов на цилиндр", "code": "Код двигателя", "grm": "ГРМ", "gearbox": "Коробка передач", "gears": "Количество передач", "drive": "Тип привода", "accel": "Разгон до 100 км/ч", "top_speed": "Максимальная скорость", "fuel_cons": "Расход топлива", "fuel_brand": "Марка топлива", "weight": "Снаряженная масса", "gross_weight": "Полная масса", "fuel_system": "Система питания", "compression": "Степень сжатия", "bore_stroke": "Диаметр цилиндра и ход поршня", "trunk": "Объём багажника", "tank": "Объём топливного бака", "eco": "Экологический стандарт", "co2": "Выброс CO2"}
    n = {}
    for g, items in spec.items():
        nl = []
        for k, v in items:
            rp = False
            for p, rk in MAP.items():
                if k == rk and p in kw: nl.append((k, kw[p])); rp = True; break
            if not rp: nl.append((k, v))
        n[g] = nl
    return n

