def ensure_brand(cur):
    cur.execute("SELECT id FROM vehicle_brands WHERE slug = 'land-rover'")
    row = cur.fetchone()
    if row: print(f"  = Brand exists (id={row[0]})"); return row[0]
    cur.execute("INSERT INTO vehicle_brands (name, slug, is_active, created_at, updated_at) VALUES ('Land Rover', 'land-rover', true, NOW(), NOW()) RETURNING id")
    bid = cur.fetchone()[0]; print(f"  + Brand (id={bid})"); return bid

def ensure_models(cur, brand_id):
    for slug, name in REQUIRED_MODELS.items():
        cur.execute("SELECT id FROM vehicle_models WHERE vehicle_brand_id = %s AND slug = %s", (brand_id, slug))
        row = cur.fetchone()
        if not row:
            cur.execute("INSERT INTO vehicle_models (vehicle_brand_id, name, slug, year_from, is_active, created_at, updated_at) VALUES (%s, %s, %s, 0, true, NOW(), NOW()) RETURNING id", (brand_id, name, slug))
            print(f"  + Model: {name} (id={cur.fetchone()[0]})")
        else: print(f"  = Model exists: {name} (id={row[0]})")

def deactivate_old(cur, brand_id):
    for s in OLD_MODEL_SLUGS:
        cur.execute("UPDATE vehicle_models SET is_active=false WHERE vehicle_brand_id=%s AND slug=%s AND is_active=true", (brand_id, s))
        if cur.rowcount: print(f"  - Deactivated model: {s}")
    for s in OLD_GENERATION_SLUGS:
        cur.execute("UPDATE vehicle_generations SET is_active=false WHERE slug=%s AND is_active=true", (s,))
        if cur.rowcount: print(f"  - Deactivated gen: {s}")

def seed_generations(cur, brand_id):
    inserted = 0
    for model_slug, gens in GENERATIONS.items():
        cur.execute("SELECT id FROM vehicle_models WHERE vehicle_brand_id = %s AND slug = %s", (brand_id, model_slug))
        mr = cur.fetchone()
        if not mr: print(f"  SKIP: {model_slug}"); continue
        mid = mr[0]
        for si, (gn, gs, yf, yt) in enumerate(gens):
            cur.execute("SELECT id FROM vehicle_generations WHERE slug = %s", (gs,))
            ex = cur.fetchone()
            if ex:
                cur.execute("UPDATE vehicle_generations SET vehicle_model_id=%s, name=%s, year_from=%s, year_to=%s, sort_order=%s, is_active=true, updated_at=NOW() WHERE slug=%s", (mid, gn, yf, yt, si, gs))
                print(f"  ~ Updated: {gs}")
            else:
                cur.execute("INSERT INTO vehicle_generations (vehicle_model_id, name, slug, year_from, year_to, is_active, sort_order, created_at, updated_at) VALUES (%s, %s, %s, %s, %s, true, %s, NOW(), NOW()) RETURNING id", (mid, gn, gs, yf, yt, si))
                print(f"  + Gen: {gs} (id={cur.fetchone()[0]})"); inserted += 1
    return inserted

def seed_specs(cur):
    ok = 0
    for gs, mods in SPECS_DATA.items():
        cur.execute("SELECT id FROM vehicle_generations WHERE slug = %s", (gs,))
        row = cur.fetchone()
        if not row: print(f"  SKIP specs: {gs}"); continue
        gid = row[0]
        sj = make_specs(mods[0][1]) if len(mods)==1 else make_modification_specs(mods)
        cur.execute("SELECT id FROM vehicle_generation_specs WHERE vehicle_generation_id = %s", (gid,))
        ex = cur.fetchone()
        js = json.dumps(sj, ensure_ascii=False)
        if ex: cur.execute("UPDATE vehicle_generation_specs SET specs = %s, updated_at = NOW() WHERE vehicle_generation_id = %s", (js, gid))
        else: cur.execute("INSERT INTO vehicle_generation_specs (vehicle_generation_id, specs, created_at, updated_at) VALUES (%s, %s, NOW(), NOW())", (gid, js))
        print(f"  + Specs: {gs} ({len(mods)} mod(s))"); ok += 1
    return ok

def main():
    print("="*60); print("4WD.az - Land Rover Full Catalog Seeder"); print("="*60)
    conn = get_db(); cur = conn.cursor()
    print("\n[1] Brand..."); bid = ensure_brand(cur)
    print("\n[2] Models..."); ensure_models(cur, bid)
    print("\n[3] Deactivate old..."); deactivate_old(cur, bid)
    print("\n[4] Generations..."); gc = seed_generations(cur, bid)
    print("\n[5] Specs..."); sc = seed_specs(cur)
    conn.commit(); cur.close(); conn.close()
    print(f"\n{'='*60}\nDone! Gens: {gc} new, Specs: {sc} upserted\n{'='*60}")

if __name__ == "__main__": main()
